serverCode:
$agenda = $params["agenda_kanwil"];
$records = $params["records"];

foreach ($records as $rec) {
    $nsm = db_prepare_string($rec["nsm"]);
    $tahun = db_prepare_string($rec["tahun"]);

    $sql = "UPDATE daftar SET no_agenda_kanwil = $agenda 
            WHERE nsm = $nsm AND tahun = $tahun";
    DB::Exec($sql);
}

